def grade_exact(actual: str, expected: str) -> bool:
    """Strict string equality after normalization."""
    def normalize(s: str) -> str:
        return s.strip().lower()
    return normalize(actual) == normalize(expected)

# Example
print(grade_exact("Paris", "paris"))   # True
print(grade_exact("Paris.", "paris"))  # False — punctuation not stripped here

import re, json

def grade_json_valid(actual: str, _expected) -> bool:
    """Pass if output is valid JSON."""
    try:
        json.loads(actual)
        return True
    except json.JSONDecodeError:
        return False

def grade_json_fields(actual: str, expected_keys: list[str]) -> bool:
    """Pass if output is valid JSON with all required fields."""
    try:
        obj = json.loads(actual)
        return all(k in obj for k in expected_keys)
    except json.JSONDecodeError:
        return False

def grade_regex(actual: str, pattern: str) -> bool:
    """Pass if output matches a regex pattern."""
    return bool(re.search(pattern, actual))

# Examples
print(grade_json_valid('{"name": "Alice"}', None))           # True
print(grade_json_fields('{"name":"Alice"}', ["name","age"])) # False — missing age
print(grade_regex("Call us at 555-1234", r"\d{3}-\d{4}")) # True

import ast, traceback

def grade_code_output(actual_code: str, test_cases: list[dict]) -> float:
    """
    Execute the model's code against test cases.
    Returns fraction of test cases that pass.
    """
    namespace = {}
    try:
        exec(compile(ast.parse(actual_code), "<model>", "exec"), namespace)
    except Exception:
        return 0.0  # Code doesn't compile or run

    passed = 0
    for tc in test_cases:
        fn_name = tc["function"]
        args = tc["args"]
        expected = tc["expected"]
        try:
            result = namespace[fn_name](*args)
            if result == expected:
                passed += 1
        except Exception:
            pass  # Runtime error on this test case

    return passed / len(test_cases)

# Usage
code = """
def add(a, b):
    return a + b
"""
tests = [
    {"function": "add", "args": [1, 2], "expected": 3},
    {"function": "add", "args": [0, 0], "expected": 0},
    {"function": "add", "args": [-1, 1], "expected": 0},
]
print(grade_code_output(code, tests))  # 1.0 — all pass

from typing import Any

def make_grader(grader_type: str, **kwargs):
    """Factory that returns a grader function."""

    def exact_match(actual: str, expected: str) -> float:
        return float(actual.strip().lower() == expected.strip().lower())

    def contains_keyword(actual: str, expected: str) -> float:
        keywords = expected.split(",")
        return float(all(kw.strip().lower() in actual.lower() for kw in keywords))

    def f1_score(actual: str, expected: str) -> float:
        """Token-level F1 between actual and expected."""
        actual_tokens = set(actual.lower().split())
        expected_tokens = set(expected.lower().split())
        if not expected_tokens:
            return 1.0 if not actual_tokens else 0.0
        precision = len(actual_tokens & expected_tokens) / len(actual_tokens) if actual_tokens else 0.0
        recall = len(actual_tokens & expected_tokens) / len(expected_tokens)
        if precision + recall == 0:
            return 0.0
        return 2 * precision * recall / (precision + recall)

    graders = {
        "exact": exact_match,
        "contains": contains_keyword,
        "f1": f1_score,
    }
    return graders[grader_type]

# Usage
grader = make_grader("f1")
print(grader("The quick brown fox", "quick fox jumps"))  # ~0.57

def composite_grader(actual: str, expected: dict) -> float:
    """
    Composite grader: must pass format check AND content check.
    expected = {"json_keys": [...], "contains": "..."}
    """
    import json

    # Check 1: valid JSON
    try:
        obj = json.loads(actual)
    except json.JSONDecodeError:
        return 0.0  # Hard fail on format

    # Check 2: required keys
    keys = expected.get("json_keys", [])
    if not all(k in obj for k in keys):
        return 0.5  # Partial credit — valid JSON but missing fields

    # Check 3: content keyword
    keyword = expected.get("contains", "")
    if keyword and keyword.lower() not in actual.lower():
        return 0.75  # Has structure but missing key content

    return 1.0  # Full credit
